INSERT INTO NIC78B
(SSPS_DL_CRT_DT
,DL_P_RNMCNO       
,HNDL_DY_TM
,HNDL_P_ENO)
SELECT 
 #{SSPS_DL_CRT_DT}
,#{RNMCNO}
,SYSDATE
,#{HNDL_P_ENO}
FROM DUAL
WHERE 1=1
    AND NOT EXISTS (
    	SELECT 1
    	  FROM NIC78B
    	 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
    	   AND DL_P_RNMCNO = #{RNMCNO}
    )

UPDATE NIC79B T1
 SET ( BSNSG_FNDTN_DT) 
      = ( SELECT FNDTN_DT 
     FROM NIC03B T2
     WHERE RNMCNO = T1.DL_P_RNMCNO
 )
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
   AND DL_P_RNMCNO = #{RNMCNO}

 INSERT INTO NIC102B
 (   SSPS_DL_CRT_DT
   , SSPS_DL_ID
   , SQ 
   , SSPS_DL_CRT_CCD 
   , GNL_AC_NO 
   , AFPR_NM
   , AFPR_RNMCNO
   , HNDL_DY_TM 
   , HNDL_P_ENO
 )
  ( SELECT
			  #{SSPS_DL_CRT_DT}
			  , #{SSPS_DL_ID}
			  , (SELECT NVL(MAX(SQ), 0) + 1 FROM NIC102B WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT} AND SSPS_DL_ID = #{SSPS_DL_ID} )
			  , 'STR'
			  , #{GNL_AC_NO}
			  , CS_NM
			  , RNMCNO
			  , SYSDATE
			  , #{HNDL_P_ENO}
     FROM NIC01B T1
    WHERE RNMCNO = #{RNMCNO}
      AND NOT EXISTS (
     					SELECT 1
    					  FROM NIC102B
    					 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}
    					   AND SSPS_DL_ID = #{SSPS_DL_ID}
    					   AND AFPR_RNMCNO = #{RNMCNO}
    )
 )

mapper.select:
SELECT /*+ FULL(A) INDEX(B SSQ.NIC_61B_IX1) */ -- 2021.01.07 힌트 추가, 2021.01.06 DBA 가이드로 힌트 제거 FULL(B) PARALLEL(B 8) A.DL_DT, -- 거래일자 TO_CHAR(TO_DATE(A.DL_TM,'HH24MISS'),'HH24:MI:SS') DL_TM, -- 거래시간 A.DL_SQ, -- 거래일련번호 A.DL_TYP_CD, -- 거래수단코드 GET_CODE_NAME('M045',A.DL_TYP_CD) AS DL_TYP_NM, -- 거래종류명 '' AS SMRY_TYP_CD, -- 적요유형코드 '' AS SMRY_TYP_NM, A.DL_WY_CD, -- 거래수단코드 GET_CODE_NAME('M046',A.DL_WY_CD) as DL_WY_NM, -- 거래수단명 A.DL_CHNNL_CD, -- 거래채널코드 GET_CODE_NAME('M044',A.DL_CHNNL_CD) AS DL_CHNNL_NM, -- 거래채널명 A.DL_AMT, -- 거래금액 A.CSH, -- 현금 A.CHCK_AMT, -- 수표금액 A.ADJST_AMT AS EC_AMT, -- 정산금액 A.TFND_RA, -- 예수금잔액 0 AS LN_AMT, -- 대출원금상환금액 '' AS SPC, -- 거래매체 A.RLTV_FNC_ACNT_NO_CRYP AS CPRTY_TRSNS_AC_NO, -- 상대대체계좌번호 A.RLTV_BANK_ACNT_NAME AS CPRTY_TRSNS_AC_NM, -- 상대대체계좌명 A.RLBK_CODE AS CPRTY_TRSNS_OGN_CD, -- 상대대체기관코드 '' AS CPRTY_TRSNS_OGN_NM, A.RLBK_NAME AS CPRTY_TRSNS_FOGN_NM, -- 상대대체금융기관명 A.CRNCY_CD, -- 통화코드 GET_CODE_NAME('M048',A.CRNCY_CD) AS CRNCY_NM, A.FCRNCY_DL_AMT, -- 외화거래금액 A.USD_EXCH_AMT, -- 달러환산금액 A.DL_Q, -- 거래수량 A.DL_UPRC, -- 거래단가 A.STND_IS_CD, -- 표준종목코드 A.STND_IS_NM, -- 표준종목코드명 '' AS STR_DL_KND_CD, -- STR거래종류코드 '' AS STR_DL_KND_NM, A.HANDLNG_BRN_CD, -- 취급지점코드 Fn_Cdinfo_Var('DPT',A.HANDLNG_BRN_CD,'') AS HANDLNG_BRN_NM, -- 취급지점명 A.L_HNDL_P_ENO, -- 처리자사번 Fn_Cdinfo_Var('USER',A.L_HNDL_P_ENO,'') AS HNDL_P_ENO_NM, -- 처리자명 '' AS CRCT_CCD, -- 정정구분코드 '' AS CHRG_P_RPR_ST_CCD, -- 담당자보고상태구분코드 '' AS RPR_TRGT_XCL_DL_CCD, -- 보고대상제외거래구분코드 '' AS SSPS_DL_CRT_DT, -- 혐의거래생성일자 '' AS SSPS_DL_ID, -- 혐의거래ID A.GNL_AC_NO, -- 종합계좌번호 C.CS_NM AS DL_P_NM, TRIM(B.ACNT_NO) AS ACNT_NO, A.GDS_NO -- 상품번호 FROM NIC61B A , NIC17B B , NIC01B C WHERE A.GNL_AC_NO = B.GNL_AC_NO AND A.DL_DT BETWEEN #{stDate} AND #{edDate} AND B.ACNT_NO = #{ACNT_NO}
AND A.DL_TYP_CD = #{DL_TYP_CD}
AND A.RNMCNO = C.RNMCNO ORDER BY A.GNL_AC_NO, A.DL_DT, A.DL_TM, A.DL_SQ

SELECT '0' AS SELECTED , (T1.SSPS_DL_CRT_DT || '-' || T1.SSPS_DL_ID) AS SSPS_DL_CRT_DT_A , T2.CS_NM AS DL_P_NM , FN_CDINFO_VAR('NO',T1.DL_P_RNMCNO,'') AS DL_P_RNMCNO_VIEW , GET_CODE_NAME('M002',T2.RNM_CNFR_CCD) AS DL_P_RNM_NO_CCD_NM , GET_SYNARIO_NAME(T1.SSPS_TYP_CD) AS SSPS_TYP_NM , T3.LST_RSK_EAL_SOR AS RSK_GRD_MRK , T3.RSK_GRD_CD AS RSK_GRD_CD , GET_CODE_NAME('A004',T3.RSK_GRD_CD) AS RSK_GRD_CD_NM , T1.RSK_MRK AS RSK_MRK , T1.RSK_GRD_CD AS RSK_GRD , GET_CODE_NAME('A004',T1.RSK_GRD_CD) AS RSK_GRD_NM , T1.DL_P_RNMCNO , V1.ACT_NAME , (NVL(T1.OK_CCD, '0')) AS OK_CCD , T1.XCL_RSN_CNTNT , T1.SSPS_DL_CRT_DT , T1.SSPS_DL_ID , T1.INST_ID , V1.WORK_ID , V1.ACT_ID , V1.PAR_INST_ID -- , T4.MN_DL_BRN_NM AS MN_DL_BRN_NM -- 처리점 -- , T4.MN_DL_BRN_CD AS MN_DL_BRN_CD -- 처리점 , ' ' AS MN_DL_BRN_NM -- 처리점 , ' ' AS MN_DL_BRN_CD -- 처리점 , G.ACNT_NO , T2.CS_NO , T2.CS_NO AS AML_CUST_ID , T1.XCL_RSN_CNTNT , DECODE((SELECT COUNT(*) FROM NIC40B WHERE BAS_YYMM = TO_CHAR(ADD_MONTHS(TO_DATE(T1.SSPS_DL_CRT_DT, 'YYYYMMDD'),-1),'YYYYMM') AND RNMCNO=T1.DL_P_RNMCNO),0,'','Y') AS LGA_AST_YN , DECODE((SELECT COUNT(*) FROM NIC66B WHERE SSPS_DL_CRT_DT >= TO_CHAR(ADD_MONTHS(TO_DATE(T1.SSPS_DL_CRT_DT,'YYYYMMDD'),-3),'YYYYMMDD') AND SSPS_DL_CRT_CCD IN ('STR','KYC') AND DL_P_RNMCNO = T1.DL_P_RNMCNO AND RPR_PRGRS_CCD = '99'),0,'','Y') STR_RPR_YN , (SELECT SPRN_KEEP_TAGT_YN FROM NIC70B WHERE SSPS_DL_CRT_DT = T1.SSPS_DL_CRT_DT AND DL_P_RNMCNO = T1.DL_P_RNMCNO ) AS SPRN_KEEP_TAGT_YN FROM NIC66B T1 , NIC01B T2 , NIC35B T3 -- , NIC73B T4 , ( SELECT A.INST_ID , A.WORK_ID , A.ACT_NAME , A.ACT_ID , D.SSPS_DL_CRT_DT , D.SSPS_DL_ID , A.PAR_INST_ID FROM V_WF_STANDBY A , NIC66B D WHERE ((A.PERSON_YN='Y') OR (A.PERSON_YN='N' AND A.PARTICIPANT_ID IN (SELECT BB.DEP_ID || '.' || ROLE_ID FROM C_USER_GROUP_ROLE AA, C_USER BB WHERE AA.USER_ID = BB.USER_ID AND BB.DEP_ID || '.' || ROLE_ID = #{param2} ) ) ) AND D.INST_ID = A.PAR_INST_ID AND D.RPR_PRGRS_CCD = '2' AND A.INST_STATUS_CD != 'RETURNED' /*회수제외*/) V1 , (SELECT SSPS_DL_CRT_DT , SSPS_DL_ID , GNL_AC_NO , MN_DL_DPRT_CD , MN_DL_DPRT_NM , PRFT_BRN_CD , PRFT_BRN_NM , ACNT_NO FROM NIC71B WHERE (SSPS_DL_CRT_DT, SSPS_DL_ID, GNL_AC_NO) IN (SELECT SSPS_DL_CRT_DT, SSPS_DL_ID, MIN(GNL_AC_NO) FROM NIC71B GROUP BY SSPS_DL_CRT_DT, SSPS_DL_ID) ) G WHERE T1.DL_P_RNMCNO = T2.RNMCNO AND T1.DL_P_RNMCNO = T3.RNMCNO(+) AND T1.SSPS_DL_CRT_DT = V1.SSPS_DL_CRT_DT AND T1.SSPS_DL_ID = V1.SSPS_DL_ID AND T1.SSPS_DL_CRT_DT = G.SSPS_DL_CRT_DT(+) AND T1.SSPS_DL_ID = G.SSPS_DL_ID(+) -- AND T1.SSPS_DL_CRT_DT = T4.SSPS_DL_CRT_DT -- AND T1.SSPS_DL_ID = T4.SSPS_DL_ID AND T1.SSPS_DL_CRT_CCD NOT IN ('CTR', 'CAC')
AND T1.SSPS_DL_CRT_DT BETWEEN #{stDate} AND #{edDate}
AND #{branchCode} IN (SELECT MN_DL_BRN_CD FROM NIC73B WHERE SSPS_DL_CRT_DT = T1.SSPS_DL_CRT_DT AND SSPS_DL_ID = T1.SSPS_DL_ID)
AND T2.CS_NM like '%' || #{CS_NM} || '%'
AND T2.CS_NO = #{CS_NO}
AND T1.SSPS_TYP_CD = #{SSPS_TYP_CD}
ORDER BY T1.SSPS_DL_CRT_DT DESC, T1.SSPS_DL_ID ASC

mapper.update:
UPDATE NIC66B SET
           OK_CCD = #{OK_CCD}            
         , HNDL_DY_TM = SYSDATE 
         , HNDL_P_ENO = #{USERID}      
 WHERE SSPS_DL_CRT_DT = #{SSPS_DL_CRT_DT}  
     AND SSPS_DL_ID = #{SSPS_DL_ID}

INSERT INTO NIC66B_W (
  INST_ID 
, WORK_ID
, MN_DL_BRN_CD
, RPR_PRGRS_CCD
, DPRT_CD
, DPRT_NM
, RPR_P_ENO
, RPR_P_NM
, RPR_P_DY_TM
, RPR_P_TEL_NO
, CNTNT
, OK_CCD
, PAR_INST_ID 
) VALUES (
  #{INST_ID} 
, #{WORK_ID}
, #{MN_DL_BRN_CD}
, #{RPR_PRGRS_CCD}
, #{DPRT_CD}
, #{DPRT_NM}
, #{RPR_P_ENO}
, #{RPR_P_NM}
, TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS')
, #{RPR_P_TEL_NO}
, #{CNTNT}
, #{OK_CCD}
, #{INST_ID}
)
